Material.Shader:

/* This is a vertex program for ...
 */

void main()
{
  vec3 normal = normalize(gl_Normal);
  vec4 lp = gl_LightSource[0].position;
  vec3 V = normalize(gl_ModelViewMatrixInverse * vec4(0.0, 0.0, 0.0, 1.0)).xyz;
  vec3 L = normalize(lp.xyz - gl_Vertex.xyz);
  vec3 R = normalize(2.0 * normal * dot(normal, L) - L);
  gl_FrontColor = gl_BackColor = gl_Color * dot(R, V);

  gl_Position = ftransform();
}



/* This is a fragment program ...
 */
uniform int NumLights;

void main()
{
	gl_FragColor = vec4(gl_Color.xyz, 1.0);
}
